import { Component, Inject, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { Supercategory } from '../interfaces/supercategory.model';
import { SuperCategoryService } from '../supercategory.service';

@Component({
  selector: 'ux-supercategory-create-update',
  templateUrl: './supercategory-create-update.component.html',
  styleUrls: ['./supercategory-create-update.component.scss']
})
export class SupercategoryCreateUpdateComponent implements OnInit {

  form: UntypedFormGroup;
  mode: 'create' | 'update' = 'create';

  constructor(@Inject(MAT_DIALOG_DATA) public defaults: any,
              private dialogRef: MatDialogRef<SupercategoryCreateUpdateComponent>,
              private fb: UntypedFormBuilder,
              private supercategoryService: SuperCategoryService
              ) {
  }

  ngOnInit() {
    if (this.defaults) {
      this.mode = 'update';
    } else {
      this.defaults = {} as Supercategory;
    }

    this.form = this.fb.group({
      super_category_id: this.defaults._id || '',
      super_category_name: this.defaults.super_category_name,
      super_category_code: [this.defaults.super_category_code || ''],
      super_category_description: [this.defaults.super_category_description || ''],
      status: this.defaults.status || '1'
    });
  }

  save() {
    if (this.mode === 'create') {
      this.createSupercategory();
    } else if (this.mode === 'update') {
      this.updateSupercategory();
    }
  }

  createSupercategory() {
    const supercategory = this.form.value;
    this.dialogRef.close(supercategory);
  }

  updateSupercategory() {
    const supercategory = this.form.value;
    supercategory._id = this.defaults._id;

    this.dialogRef.close(supercategory);
  }

  isCreateMode() {
    return this.mode === 'create';
  }

  isUpdateMode() {
    return this.mode === 'update';
  }
}
